function StatusMessage({ status, message, retryCount }) {
  return (
    <div>
      {status === 'loading'
        ? <Spinner />
        : status === 'error'
          ? retryCount > 3
            ? <p>Failed after {retryCount} tries: {message}</p>
            : <p>Error: {message}. Retrying...</p>
          : status === 'success'
            ? <p>Done: {message}</p>
            : <p>Idle</p>}
    </div>
  );
}
